}

function eventPosition(event) {
  const source = event && event.event ? event.event : event || {};
  return {
    x: Number(source.zrX ?? event.offsetX ?? 0),
    y: Number(source.zrY ?? event.offsetY ?? 0)
  };
}

function tooltipGraphic() {
