  const x = tooltip ? Math.min(chart.getWidth() - 290, Math.max(8, tooltip.x + 14)) : 0;
  const y = tooltip ? Math.min(chart.getHeight() - 210, Math.max(8, tooltip.y + 14)) : 0;
