}

function partOptionsFor(subdetector) {
  if (subdetector === "TBPX") return [
    { value: "complete", label: "Complete" },
    { value: "ladder+z+", label: "Ladder (+) Z (+)" }, { value: "ladder+z-", label: "Ladder (+) Z (-)" },
    { value: "ladder-z+", label: "Ladder (-) Z (+)" }, { value: "ladder-z-", label: "Ladder (-) Z (-)" }
  ];
  return [
    { value: "complete", label: "Complete" },
    { value: "left+z", label: "Left (+Z side)" }, { value: "right+z", label: "Right (+Z side)" },
    { value: "left-z", label: "Left (-Z side)" }, { value: "right-z", label: "Right (-Z side)" }
  ];
}

function ringCard(view, width, height) {
  const children = [];
  const layout = view.subdetector === "TFPX" ? cfg.forwardLayout : cfg.endcapLayout;
  const geometry = view.subdetector === "TFPX" ? cfg.forwardGeometry : cfg.endcapGeometry;
  const side = view.part.endsWith("+z") ? "+z" : "-z";
  const half = view.part.indexOf("right") === 0 ? "upper" : "lower";
  const cx = width / 2;
  const cy = height / 2 + 18;
  const maxRadius = Math.min(width * 0.38, height * 0.44);
  const physicalOuter = Math.max.apply(null, Object.values(layout.rings).map(function(ring) { return ring.outer_radius; }));
  const scale = maxRadius / physicalOuter;
  const map = {};
  Object.entries(geometry).forEach(function(entry) {
    const key = entry[0];
    const item = entry[1];
    map[[item.detector_side, item.disk, item.ring, item.half, item.module_index].join(":")] = key;
  });
  children.push(text(16, 24, view.subdetector + "  Disk " + view.element + "  |  " + optionLabel(partOptionsFor(view.subdetector), view.part), 15, "bold"));
  Object.keys(layout.rings).forEach(function(ringKey) {
    const ring = layout.rings[ringKey];
    const count = ring.modules_per_half;
    const surface = DISK_SURFACE_COLORS[ring.disk_surface];
    const halfStart = (half === "upper" ? Math.PI : 0) + DISK_ROTATION;
    children.push({
      type: "sector",
      silent: true,
      shape: {
        cx: cx,
        cy: cy,
        r0: ring.inner_radius * scale,
        r: ring.outer_radius * scale,
        startAngle: halfStart,
        endAngle: halfStart + Math.PI,
        clockwise: true
      },
      style: { fill: surface.fill, stroke: surface.line, lineWidth: 1 }
    });
    for (let moduleIndex = 0; moduleIndex < count; moduleIndex++) {
      const pitch = Math.PI / count;
      const centre = halfStart + (moduleIndex + 0.5) * pitch;
      const moduleWidth = pitch * MODULE_GAP_FACTOR;
      const start = centre - moduleWidth / 2;
      const end = centre + moduleWidth / 2;
      const key = map[[side, view.element, ringKey, half, moduleIndex].join(":")];
      const chipRows = ring.module_type === "double" ? 1 : 2;
      const chipLayout = ring.module_type === "double" ? cfg.doubleChipLayout : cfg.quadChipLayout;
      Object.keys(chipLayout).forEach(function(chip) {
        const position = chipLayout[chip];
        const chipStart = start + position[0] * (end - start) / 2;
        const chipEnd = chipStart + (end - start) / 2;
        const radialWidth = (ring.outer_radius - ring.inner_radius) / chipRows;
        const outer = ring.outer_radius - position[1] * radialWidth;
        const inner = outer - radialWidth;
        const chipData = (valuesByHardware[key] || {})[chip];
        const baseStroke = chipData ? "#111111" : "rgba(190,190,190,0.25)";
        children.push({
          type: "sector",
          cursor: chipData ? "pointer" : "default",
          shape: { cx: cx, cy: cy, r0: inner * scale, r: outer * scale, startAngle: chipStart, endAngle: chipEnd, clockwise: true },
          style: {
            fill: colorFor(chipData && chipData.value),
            stroke: baseStroke,
            lineWidth: 1
          },
          onmouseover: function(event) {
            if (!chipData) return;
            this.attr({ style: { fill: colorFor(chipData.value), stroke: "#ffffff", lineWidth: 2.3, shadowBlur: 12, shadowColor: "rgba(120,200,255,0.65)" } });
            showTooltip(event, chipTooltip(view, chipData, chip, [
              "Disk " + view.element,
              "Detector side: " + side,
              "Disk half: " + (half === "upper" ? "Right" : "Left"),
              "Ring: " + ringKey,
              "Module: " + moduleIndex,
              "Disk surface: " + (ring.disk_surface === "inner" ? "Inner Disk" : "Outer Disk")
            ]));
          },
          onmouseout: function() {
            if (!chipData) return;
            this.attr({ style: { fill: colorFor(chipData.value), stroke: baseStroke, lineWidth: 1, shadowBlur: 0, shadowColor: "transparent" } });
            hideTooltip();
          },
          onclick: function() { if (chipData) openDetail(chipData, chip, view.id); }
        });
        if (chipData) {
          const labelAngle = (chipStart + chipEnd) / 2;
          const labelRadius = (inner + outer) * scale / 2;
          children.push({
            type: "text",
            silent: true,
            style: {
              x: cx + labelRadius * Math.cos(labelAngle),
              y: cy + labelRadius * Math.sin(labelAngle),
              text: chipData.value.toFixed(1),
              fill: "#111111",
              font: "bold 9px sans-serif",
              textAlign: "center",
              textVerticalAlign: "middle"
            }
          });
        }
      });
      const meta = moduleMeta(key);
      children.push({
        type: "group",
        cursor: meta.board ? "pointer" : "default",
        onmouseover: function(event) {
          if (!meta.board) return;
          moduleHover(this, true, "rgba(205,205,205,0.55)");
          showTooltip(event, [
            view.subdetector + "  Disk " + view.element,
            "Detector side: " + side,
            "Disk half: " + (half === "upper" ? "Right" : "Left"),
            "Ring: " + ringKey,
            "Module: " + moduleIndex,
            "Disk surface: " + (ring.disk_surface === "inner" ? "Inner Disk" : "Outer Disk"),
            "Board: " + meta.board,
            "Optical group: " + meta.optical_group,
            "Hybrid: " + meta.hybrid,
            "Click to open all module chips"
          ]);
        },
        onmouseout: function() { moduleHover(this, false, "rgba(205,205,205,0.55)"); hideTooltip(); },
        onclick: function() { openDetail(meta, "All", view.id); },
        children: [
          {
            type: "sector",
            shape: { cx: cx, cy: cy, r0: ring.inner_radius * scale, r: ring.outer_radius * scale, startAngle: start, endAngle: end, clockwise: true },
            style: { fill: null, stroke: "rgba(255,255,255,0.001)", lineWidth: 9 }
          },
          {
            type: "sector",
            silent: true,
            shape: { cx: cx, cy: cy, r0: ring.inner_radius * scale, r: ring.outer_radius * scale, startAngle: start, endAngle: end, clockwise: true },
            style: { fill: null, stroke: "rgba(205,205,205,0.55)", lineWidth: 1 }
          }
        ]
      });
    }
  });
  children.push(text(cx, cy, side, 12, "bold", "center"));
  children.push(text(cx, height - 18, half === "upper" ? "Right half" : "Left half", 12, "bold", "center"));
  children.push(rect(width - 210, height - 31, 13, 10, DISK_SURFACE_COLORS.inner.fill, DISK_SURFACE_COLORS.inner.line, 1, 0));
  children.push(text(width - 191, height - 26, "Inner Disk", 10, "normal"));
  children.push(rect(width - 112, height - 31, 13, 10, DISK_SURFACE_COLORS.outer.fill, DISK_SURFACE_COLORS.outer.line, 1, 0));
  children.push(text(width - 93, height - 26, "Outer Disk", 10, "normal"));
  return children;
}

function completeBarrelCard(view, width, height) {
  const children = [];
  const layer = cfg.barrelLayout[view.element];
  const ladderCount = layer.half_ladders;
  const negativeColumns = layer.z_minus_modules;
  const positiveColumns = layer.z_plus_modules;
  const left = 64;
  const top = 56;
  const plotWidth = width - 94;
  const plotHeight = height - 108;
  const moduleWidth = plotWidth / (negativeColumns + positiveColumns + 1);
  const verticalGap = moduleWidth;
  const horizontalGap = Math.max(16, Math.min(32, plotHeight * 0.055));
  const negativeQuadrantWidth = negativeColumns * moduleWidth;
  const positiveQuadrantWidth = positiveColumns * moduleWidth;
  const quadrantHeight = (plotHeight - horizontalGap) / 2;
  const moduleHeight = quadrantHeight / ladderCount;
  const centreX = left + negativeQuadrantWidth + verticalGap / 2;
  const centreY = top + quadrantHeight + horizontalGap / 2;
  const map = {};

  Object.entries(cfg.barrelGeometry).forEach(function(entry) {
    const key = entry[0];
    const item = entry[1];
    map[[item.layer, item.signed_ladder, item.z_side, item.module_index].join(":")] = key;
  });

  const moduleDescription = layer.module_type === "double" ? "Double module 1x2" : "Quad module 2x2";
  children.push(text(16, 24, "Layer " + view.element + "  |  " + moduleDescription + "  |  " + (ladderCount * 2) + " ladders", 15, "bold"));
  children.push(text(left + plotWidth / 2, height - 18, "Module position along z", 12, "bold", "center"));
  children.push({
    type: "text",
    rotation: -Math.PI / 2,
    x: 18,
    y: top + plotHeight / 2,
    silent: true,
    style: { text: "Signed ladder", fill: "#dfe4eb", font: "bold 12px sans-serif", textAlign: "center" }
  });
  children.push({
    type: "line",
    silent: true,
    shape: {
      x1: centreX,
      y1: top,
      x2: centreX,
      y2: top + plotHeight
    },
    style: { stroke: "rgba(220,228,238,0.88)", lineWidth: 1.2 }
  });
  children.push({
    type: "line",
    silent: true,
    shape: {
      x1: left,
      y1: centreY,
      x2: left + plotWidth,
      y2: centreY
    },
    style: { stroke: "rgba(220,228,238,0.88)", lineWidth: 1.2 }
  });
  for (let tick = 0; tick <= ladderCount; tick++) {
    [top + tick * moduleHeight, top + quadrantHeight + horizontalGap + tick * moduleHeight].forEach(function(y) {
      children.push({
        type: "line",
        silent: true,
        shape: { x1: centreX - 4, y1: y, x2: centreX + 4, y2: y },
        style: { stroke: "rgba(220,228,238,0.88)", lineWidth: 1 }
      });
    });
  }
  for (let tick = 0; tick <= negativeColumns; tick++) {
    const x = left + tick * moduleWidth;
    children.push({
      type: "line",
      silent: true,
      shape: { x1: x, y1: centreY - 4, x2: x, y2: centreY + 4 },
      style: { stroke: "rgba(220,228,238,0.88)", lineWidth: 1 }
    });
  }
  for (let tick = 0; tick <= positiveColumns; tick++) {
    const x = left + negativeQuadrantWidth + verticalGap + tick * moduleWidth;
    children.push({
      type: "line",
      silent: true,
      shape: { x1: x, y1: centreY - 4, x2: x, y2: centreY + 4 },
      style: { stroke: "rgba(220,228,238,0.88)", lineWidth: 1 }
    });
  }

  for (let signedLadder = -ladderCount; signedLadder <= ladderCount; signedLadder++) {
    if (signedLadder === 0) continue;
    const drawRow = signedLadder > 0 ? ladderCount - signedLadder : Math.abs(signedLadder) - 1;
    const y = signedLadder > 0
      ? top + drawRow * moduleHeight
      : top + quadrantHeight + horizontalGap + drawRow * moduleHeight;
    children.push(text(left - 10, y + 0.5 * moduleHeight, String(signedLadder), 10, "normal", "right"));

    ["z-", "z+"].forEach(function(zSide) {
      const moduleCount = zSide === "z-" ? negativeColumns : positiveColumns;
      for (let moduleIndex = 1; moduleIndex <= moduleCount; moduleIndex++) {
        const drawColumn = zSide === "z-"
          ? negativeColumns - moduleIndex
          : moduleIndex - 1;
        const x = zSide === "z-"
          ? left + drawColumn * moduleWidth
          : left + negativeQuadrantWidth + verticalGap + drawColumn * moduleWidth;
        const key = map[[view.element, signedLadder, zSide, moduleIndex].join(":")];
        const chipRows = layer.module_type === "double" ? 1 : 2;
        const chipWidth = moduleWidth / 2;
        const chipHeight = moduleHeight / chipRows;
        const layout = layer.module_type === "double" ? cfg.doubleChipLayout : cfg.quadChipLayout;

        Object.keys(layout).forEach(function(chip) {
          const position = layout[chip];
          const chipData = (valuesByHardware[key] || {})[chip];
          const chipX = x + position[0] * chipWidth;
          const chipY = y + position[1] * chipHeight;
          const baseStroke = chipData ? "#111111" : "rgba(180,180,180,0.25)";
          children.push({
            type: "rect",
            cursor: chipData ? "pointer" : "default",
            shape: { x: chipX, y: chipY, width: chipWidth, height: chipHeight },
            style: { fill: colorFor(chipData && chipData.value), stroke: baseStroke, lineWidth: 1 },
            onmouseover: function(event) {
              if (!chipData) return;
              this.attr({ style: { fill: colorFor(chipData.value), stroke: "#ffffff", lineWidth: 2.3, shadowBlur: 12, shadowColor: "rgba(120,200,255,0.65)" } });
              showTooltip(event, chipTooltip(view, chipData, chip, [
                "Layer " + view.element,
                "Signed ladder: " + signedLadder,
                "Z side: " + (zSide === "z+" ? "+Z" : "-Z"),
                "Module: " + moduleIndex
              ]));
            },
            onmouseout: function() {
              if (!chipData) return;
              this.attr({ style: { fill: colorFor(chipData.value), stroke: baseStroke, lineWidth: 1, shadowBlur: 0, shadowColor: "transparent" } });
              hideTooltip();
            },
            onclick: function() { if (chipData) openDetail(chipData, chip, view.id); }
          });
          if (chipData) {
            children.push({
              type: "text",
              silent: true,
              style: {
                x: chipX + chipWidth / 2,
                y: chipY + chipHeight / 2,
                text: chipData.value.toFixed(1),
                fill: "#111111",
                font: "bold " + Math.max(7, Math.min(11, chipHeight * 0.38)) + "px sans-serif",
                textAlign: "center",
                textVerticalAlign: "middle"
              }
            });
          }
        });

        const meta = moduleMeta(key);
        children.push({
          type: "group",
          cursor: meta.board ? "pointer" : "default",
          onmouseover: function(event) {
            if (!meta.board) return;
            moduleHover(this, true, "rgba(190,190,190,0.55)");
            showTooltip(event, [
              "TBPX  Layer " + view.element,
              "Signed ladder: " + signedLadder,
              "Z side: " + (zSide === "z+" ? "+Z" : "-Z"),
              "Module: " + moduleIndex,
              "Board: " + meta.board,
              "Optical group: " + meta.optical_group,
              "Hybrid: " + meta.hybrid,
              "Click to open all module chips"
            ]);
          },
          onmouseout: function() { moduleHover(this, false, "rgba(190,190,190,0.55)"); hideTooltip(); },
          onclick: function() { if (meta.board) openDetail(meta, "All", view.id); },
          children: [
            {
              type: "rect",
              shape: { x: x, y: y, width: moduleWidth, height: moduleHeight },
              style: { fill: null, stroke: "rgba(255,255,255,0.001)", lineWidth: 9 }
            },
            {
              type: "rect",
              silent: true,
              shape: { x: x, y: y, width: moduleWidth, height: moduleHeight },
              style: { fill: null, stroke: "rgba(190,190,190,0.55)", lineWidth: 1 }
            }
          ]
        });
      }
    });
  }

  for (let moduleIndex = negativeColumns; moduleIndex >= 1; moduleIndex--) {
    const drawColumn = negativeColumns - moduleIndex;
    children.push(text(left + (drawColumn + 0.5) * moduleWidth, top + plotHeight + 12, String(-moduleIndex), 10, "normal", "center"));
  }
  for (let moduleIndex = 1; moduleIndex <= positiveColumns; moduleIndex++) {
    const drawColumn = moduleIndex - 1;
    children.push(text(left + negativeQuadrantWidth + verticalGap + (drawColumn + 0.5) * moduleWidth, top + plotHeight + 12, String(moduleIndex), 10, "normal", "center"));
  }

  return children;
}

function completeRingCard(view, width, height) {
  const children = [];
  const layout = view.subdetector === "TFPX" ? cfg.forwardLayout : cfg.endcapLayout;
  const geometry = view.subdetector === "TFPX" ? cfg.forwardGeometry : cfg.endcapGeometry;
  const physicalOuter = Math.max.apply(null, Object.values(layout.rings).map(function(ring) { return ring.outer_radius; }));
  const maxRadius = Math.min(width * 0.205, height * 0.39);
  const scale = maxRadius / physicalOuter;
  const cy = height / 2 + 12;
  const centres = { "+z": width * 0.27, "-z": width * 0.73 };
  const map = {};

  Object.entries(geometry).forEach(function(entry) {
    const key = entry[0];
    const item = entry[1];
    map[[item.detector_side, item.disk, item.ring, item.half, item.module_index].join(":")] = key;
  });

  children.push(text(16, 24, view.subdetector + "  Disk " + view.element + "  |  Complete", 15, "bold"));

  ["+z", "-z"].forEach(function(side) {
    const cx = centres[side];
    children.push(text(cx, 48, side === "+z" ? "+Z detector side" : "-Z detector side", 12, "bold", "center"));
    children.push({
      type: "line",
      silent: true,
      shape: { x1: cx, y1: cy - maxRadius - 5, x2: cx, y2: cy + maxRadius + 5 },
      style: { stroke: "rgba(210,220,232,0.7)", lineWidth: 1 }
    });

    Object.keys(layout.rings).forEach(function(ringKey) {
      const ring = layout.rings[ringKey];
      const surface = DISK_SURFACE_COLORS[ring.disk_surface];
      children.push({
        type: "sector",
        silent: true,
        shape: {
          cx: cx,
          cy: cy,
          r0: ring.inner_radius * scale,
          r: ring.outer_radius * scale,
          startAngle: 0,
          endAngle: Math.PI * 2,
          clockwise: true
        },
        style: { fill: surface.fill, stroke: surface.line, lineWidth: 1 }
      });

      ["upper", "lower"].forEach(function(half) {
        const count = ring.modules_per_half;
        const halfStart = (half === "upper" ? Math.PI : 0) + DISK_ROTATION;
        for (let moduleIndex = 0; moduleIndex < count; moduleIndex++) {
          const pitch = Math.PI / count;
          const centre = halfStart + (moduleIndex + 0.5) * pitch;
          const moduleWidth = pitch * MODULE_GAP_FACTOR;
          const start = centre - moduleWidth / 2;
          const end = centre + moduleWidth / 2;
          const key = map[[side, view.element, ringKey, half, moduleIndex].join(":")];
          const chipRows = ring.module_type === "double" ? 1 : 2;
          const chipLayout = ring.module_type === "double" ? cfg.doubleChipLayout : cfg.quadChipLayout;

          Object.keys(chipLayout).forEach(function(chip) {
            const position = chipLayout[chip];
            const chipStart = start + position[0] * (end - start) / 2;
            const chipEnd = chipStart + (end - start) / 2;
            const radialWidth = (ring.outer_radius - ring.inner_radius) / chipRows;
            const outer = ring.outer_radius - position[1] * radialWidth;
            const inner = outer - radialWidth;
            const chipData = (valuesByHardware[key] || {})[chip];
            const baseStroke = chipData ? "#111111" : "rgba(190,190,190,0.25)";
            children.push({
              type: "sector",
              cursor: chipData ? "pointer" : "default",
              shape: { cx: cx, cy: cy, r0: inner * scale, r: outer * scale, startAngle: chipStart, endAngle: chipEnd, clockwise: true },
              style: { fill: colorFor(chipData && chipData.value), stroke: baseStroke, lineWidth: 1 },
              onmouseover: function(event) {
                if (!chipData) return;
                this.attr({ style: { fill: colorFor(chipData.value), stroke: "#ffffff", lineWidth: 2.3, shadowBlur: 12, shadowColor: "rgba(120,200,255,0.65)" } });
                showTooltip(event, chipTooltip(view, chipData, chip, [
                  "Disk " + view.element,
                  "Detector side: " + side,
                  "Disk half: " + (half === "upper" ? "Right" : "Left"),
                  "Ring: " + ringKey,
                  "Module: " + moduleIndex,
                  "Disk surface: " + (ring.disk_surface === "inner" ? "Inner Disk" : "Outer Disk")
                ]));
              },
              onmouseout: function() {
                if (!chipData) return;
                this.attr({ style: { fill: colorFor(chipData.value), stroke: baseStroke, lineWidth: 1, shadowBlur: 0, shadowColor: "transparent" } });
                hideTooltip();
              },
              onclick: function() { if (chipData) openDetail(chipData, chip, view.id); }
            });
            if (chipData) {
              const labelAngle = (chipStart + chipEnd) / 2;
              const labelRadius = (inner + outer) * scale / 2;
              children.push({
                type: "text",
                silent: true,
                style: {
                  x: cx + labelRadius * Math.cos(labelAngle),
                  y: cy + labelRadius * Math.sin(labelAngle),
                  text: chipData.value.toFixed(1),
                  fill: "#111111",
                  font: "bold 9px sans-serif",
                  textAlign: "center",
                  textVerticalAlign: "middle"
                }
              });
            }
          });

          const meta = moduleMeta(key);
          children.push({
            type: "group",
            cursor: meta.board ? "pointer" : "default",
            onmouseover: function(event) {
              if (!meta.board) return;
              moduleHover(this, true, "rgba(205,205,205,0.55)");
              showTooltip(event, [
                view.subdetector + "  Disk " + view.element,
                "Detector side: " + side,
                "Disk half: " + (half === "upper" ? "Right" : "Left"),
                "Ring: " + ringKey,
                "Module: " + moduleIndex,
                "Disk surface: " + (ring.disk_surface === "inner" ? "Inner Disk" : "Outer Disk"),
                "Board: " + meta.board,
                "Optical group: " + meta.optical_group,
                "Hybrid: " + meta.hybrid,
                "Click to open all module chips"
              ]);
            },
            onmouseout: function() { moduleHover(this, false, "rgba(205,205,205,0.55)"); hideTooltip(); },
            onclick: function() { if (meta.board) openDetail(meta, "All", view.id); },
            children: [
              {
                type: "sector",
                shape: { cx: cx, cy: cy, r0: ring.inner_radius * scale, r: ring.outer_radius * scale, startAngle: start, endAngle: end, clockwise: true },
                style: { fill: null, stroke: "rgba(255,255,255,0.001)", lineWidth: 9 }
              },
              {
                type: "sector",
                silent: true,
                shape: { cx: cx, cy: cy, r0: ring.inner_radius * scale, r: ring.outer_radius * scale, startAngle: start, endAngle: end, clockwise: true },
                style: { fill: null, stroke: "rgba(205,205,205,0.55)", lineWidth: 1 }
              }
            ]
          });
        }
      });
    });

    children.push(text(cx, cy, side, 12, "bold", "center"));
    children.push(text(cx - maxRadius * 0.55, cy + maxRadius + 20, "Left", 10, "bold", "center"));
    children.push(text(cx + maxRadius * 0.55, cy + maxRadius + 20, "Right", 10, "bold", "center"));
  });

  children.push(rect(width - 210, height - 31, 13, 10, DISK_SURFACE_COLORS.inner.fill, DISK_SURFACE_COLORS.inner.line, 1, 0));
  children.push(text(width - 191, height - 26, "Inner Disk", 10, "normal"));
  children.push(rect(width - 112, height - 31, 13, 10, DISK_SURFACE_COLORS.outer.fill, DISK_SURFACE_COLORS.outer.line, 1, 0));
  children.push(text(width - 93, height - 26, "Outer Disk", 10, "normal"));
  return children;
}

function viewSize(view) {
  return CARD_SIZES.indexOf(view.size) === -1 ? "medium" : view.size;
}

function resizeView(view, direction) {
  const current = CARD_SIZES.indexOf(viewSize(view));
  const next = Math.max(0, Math.min(CARD_SIZES.length - 1, current + direction));
  view.size = CARD_SIZES[next];
  savePartsRuntime();
  refresh();
}

function viewHeight(view) {
  const baseHeight = view.part === "complete"
    ? 720
    : view.subdetector !== "TBPX" ? 540 : 390;
  const scale = viewSize(view) === "small"
    ? 0.78
    : viewSize(view) === "large" ? 1.25 : 1;
  return Math.round(baseHeight * scale);
}

function card(view, x, y, width, height) {
  let body;
  if (view.part === "complete") {
    body = view.subdetector === "TBPX"
      ? completeBarrelCard(view, width, height)
      : completeRingCard(view, width, height);
  } else {
    body = view.subdetector === "TBPX"
      ? barrelCard(view, width, height)
      : ringCard(view, width, height);
  }
  body.unshift(rect(0, 0, width, height, "#181c23", "#566273", 1, 8));
  const size = viewSize(view);
  const sizeIndex = CARD_SIZES.indexOf(size);
  body.push(text(width - 215, 23, "Size " + size.charAt(0).toUpperCase(), 10, "bold", "right"));
  body.push({
    type: "group",
    x: width - 202,
    y: 10,
    cursor: sizeIndex > 0 ? "pointer" : "default",
    onclick: function() { if (sizeIndex > 0) resizeView(view, -1); },
    children: [
      rect(0, 0, 28, 26, sizeIndex > 0 ? "#26313e" : "#20252c", sizeIndex > 0 ? "#718096" : "#3f4650", 1, 5),
      text(14, 13, "-", 14, "bold", "center")
    ]
  });
  body.push({
    type: "group",
    x: width - 166,
    y: 10,
    cursor: sizeIndex < CARD_SIZES.length - 1 ? "pointer" : "default",
    onclick: function() { if (sizeIndex < CARD_SIZES.length - 1) resizeView(view, 1); },
    children: [
      rect(0, 0, 28, 26, sizeIndex < CARD_SIZES.length - 1 ? "#26313e" : "#20252c", sizeIndex < CARD_SIZES.length - 1 ? "#718096" : "#3f4650", 1, 5),
      text(14, 13, "+", 14, "bold", "center")
    ]
  });
  body.push({
    type: "group",
    x: width - 82,
    y: 10,
    cursor: "pointer",
    onclick: function() {
      runtime.views = runtime.views.filter(function(candidate) { return candidate.id !== view.id; });
      savePartsRuntime();
      refresh();
    },
    children: [rect(0, 0, 68, 26, "#34262a", "#b36b73", 1, 5), text(34, 13, "Delete", 11, "bold", "center")]
  });
  return { type: "group", x: x, y: y, children: body };
}

function buildOption() {
  const width = chart.getWidth();
  const controls = [];
  const subdetectors = [
    { value: "TBPX", label: "TBPX (Barrel)" },
    { value: "TEPX", label: "TEPX (Endcap)" },
    { value: "TFPX", label: "TFPX (Forward)" }
  ];
  controls.push(dropdown("subdetector", 18, "Subdetector", subdetectors, runtime.selection.subdetector, function(value) {
    runtime.selection.subdetector = value;
    runtime.selection.element = "1";
    runtime.selection.part = "complete";
  }));
  controls.push(dropdown("element", 246, runtime.selection.subdetector === "TBPX" ? "Layer" : "Disk", elementOptions(), runtime.selection.element, function(value) {
    runtime.selection.element = value;
  }));
  controls.push(dropdown("part", 474, runtime.selection.subdetector === "TBPX" ? "Quadrant / view" : "Disk part / view", partOptions(), runtime.selection.part, function(value) {
    runtime.selection.part = value;
  }));
  controls.push({
    type: "group", x: 702, y: 32, cursor: "pointer",
    onclick: function() {
      runtime.views.push({ id: runtime.nextId++, subdetector: runtime.selection.subdetector, element: runtime.selection.element, part: runtime.selection.part, size: "medium" });
      savePartsRuntime();
      runtime.open = null;
      refresh();
    },
    children: [rect(0, 0, 100, 32, "#245f46", "#7fc6a4", 1, 5), text(50, 16, "Add panel", 12, "bold", "center")]
  });
  const openOptionCount = runtime.open === "subdetector"
    ? subdetectors.length
    : runtime.open === "element"
      ? elementOptions().length
      : runtime.open === "part" ? partOptions().length : 0;
  const contentTop = runtime.open ? 90 + openOptionCount * 30 : 105;
  if (runtime.views.length === 0) controls.push(text(18, contentTop + 7, "Choose a detector part and select Add panel.", 14, "normal"));
  const gap = 16;
  const availableWidth = width - 36;
  const halfWidth = (availableWidth - gap) / 2;
  const useTwoColumns = width >= 1450;
  let cursorY = contentTop;
  let pendingRow = [];

  function flushRow() {
    if (pendingRow.length === 0) return;
    const rowHeight = Math.max.apply(null, pendingRow.map(function(item) { return item.height; }));
    pendingRow.forEach(function(item, index) {
      controls.push(card(item.view, 18 + index * (halfWidth + gap), cursorY, halfWidth, item.height));
    });
    cursorY += rowHeight + gap;
    pendingRow = [];
  }

  runtime.views.forEach(function(view) {
    const height = viewHeight(view);
    const fullWidth = !useTwoColumns || runtime.views.length === 1 || viewSize(view) === "large";
    if (fullWidth) {
      flushRow();
      controls.push(card(view, 18, cursorY, availableWidth, height));
      cursorY += height + gap;
      return;
    }
    pendingRow.push({ view: view, height: height });
    if (pendingRow.length === 2) flushRow();
  });
  flushRow();
  controls.push(tooltipGraphic());
  return { backgroundColor: "transparent", animationDurationUpdate: 250, animationEasingUpdate: "cubicOut", graphic: controls };
}

return buildOption();
